#!/usr/bin/env python3
# Todo CLI - Version 1
import sys

todos = []

def add_todo(task):
    todos.append(task)
    print(f'Added: {task}')

def list_todos():
    if not todos:
        print('No todos yet!')
        return
    for i, task in enumerate(todos, 1):
        print(f'{i}. {task}')

def complete_todo(index):
    todos.pop(index - 1)
    print('Todo completed!')

if __name__ == '__main__':
    if len(sys.argv) < 2:
        print('Usage: todo_app.py <add|list|done> [args]')
        sys.exit(1)

    cmd = sys.argv[1]
    if cmd == 'add':
        add_todo(' '.join(sys.argv[2:]))
    elif cmd == 'list':
        list_todos()
    elif cmd == 'done':
        complete_todo(int(sys.argv[2]))
